# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharehandler

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import android.widget.Toast

class ShareReceiverActivity : Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleShareIntent(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleShareIntent(intent)
        finish()
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> handleSingleShare(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleMultipleShare(intent)
            else -> {
                Log.w(TAG, "Unsupported intent action: ${intent.action}")
            }
        }
    }

    private fun handleSingleShare(intent: Intent) {
        val mimeType = intent.type ?: return

        when {
            mimeType.startsWith("text/") -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)
                processSharedText(sharedText, sharedSubject)
            }

            mimeType.startsWith("image/") -> {
                val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                if (imageUri != null) {
                    processSharedImage(imageUri)
                }
            }

            else -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                val sharedUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                if (sharedText != null) {
                    processSharedText(sharedText, intent.getStringExtra(Intent.EXTRA_SUBJECT))
                } else if (sharedUri != null) {
                    processSharedImage(sharedUri)
                }
            }
        }
    }

    private fun handleMultipleShare(intent: Intent) {
        val mimeType = intent.type ?: return

        if (mimeType.startsWith("image/")) {
            val uris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
            uris?.forEach { processSharedImage(it) }
        } else {
            val text = intent.getStringExtra(Intent.EXTRA_TEXT)
            if (text != null) {
                processSharedText(text, intent.getStringExtra(Intent.EXTRA_SUBJECT))
            }
        }
    }

    private fun processSharedText(text: String?, subject: String?) {
        if (text.isNullOrBlank()) return
        Log.d(TAG, "Shared text received. Subject=$subject Text=$text")
        Toast.makeText(this, "Shared text received", Toast.LENGTH_SHORT).show()
    }

    private fun processSharedImage(uri: Uri) {
        Log.d(TAG, "Shared image received: $uri")
        Toast.makeText(this, "Shared image received", Toast.LENGTH_SHORT).show()
    }

    companion object {
        private const val TAG = "ShareReceiverActivity"
    }
}

